import heapq

class StockPrice:

    def __init__(self):
        self.prices = {}
        self.latest_ts = 0
        self.max_heap = []
        self.min_heap = []
        self.lazy = set()

    def update(self, timestamp: int, price: int) -> None:
        if timestamp in self.prices:
            old_price = self.prices[timestamp]
            self.lazy.add((old_price, timestamp))
        self.prices[timestamp] = price
        heapq.heappush(self.max_heap, (-price, timestamp))
        heapq.heappush(self.min_heap, (price, timestamp))
        if timestamp >= self.latest_ts:
            self.latest_ts = timestamp

    def current(self) -> int:
        return self.prices[self.latest_ts]

    def maximum(self) -> int:
        while self.max_heap:
            neg_price, ts = self.max_heap[0]
            if (-neg_price, ts) in self.lazy:
                heapq.heappop(self.max_heap)
                self.lazy.remove((-neg_price, ts))
            else:
                return -neg_price

    def minimum(self) -> int:
        while self.min_heap:
            price, ts = self.min_heap[0]
            if (price, ts) in self.lazy:
                heapq.heappop(self.min_heap)
                self.lazy.remove((price, ts))
            else:
                return price
